UPDATE diary_circle
SET like_count = like_count + 1
WHERE id = #{id}

UPDATE diary_circle
SET like_count = GREATEST(0, like_count - 1)
WHERE id = #{id}

UPDATE diary_circle
SET comment_count = comment_count + 1
WHERE id = #{id}

UPDATE diary_circle
SET comment_count = GREATEST(0, comment_count - 1)
WHERE id = #{id}
